<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Ubuntu Desktop</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  html, body { width: 100%; height: 100%; overflow: hidden; font-family: "Segoe UI", Ubuntu, "DejaVu Sans", sans-serif; }
  body { background: #2c001e; color: #fff; }

  #desktop {
    position: fixed; inset: 0;
    background:
      radial-gradient(circle at 30% 20%, #5e2750 0%, transparent 50%),
      radial-gradient(circle at 80% 70%, #4a0e3a 0%, transparent 55%),
      linear-gradient(135deg, #2c001e 0%, #1a0014 100%);
    overflow: hidden;
  }

  /* Top bar */
  #topbar {
    position: absolute; top: 0; left: 0; right: 0; height: 28px;
    background: rgba(20, 14, 20, 0.85);
    backdrop-filter: blur(8px);
    display: flex; align-items: center; justify-content: space-between;
    padding: 0 12px; font-size: 13px; z-index: 1000;
    border-bottom: 1px solid rgba(255,255,255,0.05);
  }
  #topbar .activities { font-weight: 600; cursor: default; }
  #clock { font-variant-numeric: tabular-nums; }

  /* Taskbar / dock */
  #taskbar {
    position: absolute; bottom: 12px; left: 50%; transform: translateX(-50%);
    display: flex; gap: 8px; padding: 8px 12px;
    background: rgba(30, 20, 30, 0.75);
    backdrop-filter: blur(12px);
    border-radius: 14px;
    border: 1px solid rgba(255,255,255,0.08);
    z-index: 1000;
    box-shadow: 0 8px 24px rgba(0,0,0,0.4);
  }
  #taskbar button {
    width: 48px; height: 48px; border: none; border-radius: 10px;
    background: rgba(255,255,255,0.06); color: #fff; cursor: pointer;
    display: flex; align-items: center; justify-content: center;
    font-size: 22px; transition: background .15s, transform .15s;
  }
  #taskbar button:hover { background: rgba(255,255,255,0.16); transform: translateY(-3px); }
  #taskbar button:active { transform: translateY(0); }

  /* Windows */
  .window {
    position: absolute; min-width: 360px; min-height: 240px;
    background: #2b2b2b; color: #f1f1f1;
    border-radius: 10px; overflow: hidden;
    box-shadow: 0 18px 50px rgba(0,0,0,0.55), 0 0 0 1px rgba(0,0,0,0.5);
    display: flex; flex-direction: column;
    z-index: 10;
  }
  .window.hidden { display: none; }
  .win-titlebar {
    height: 34px; flex: 0 0 34px;
    background: linear-gradient(#3c3c3c, #303030);
    display: flex; align-items: center; padding: 0 10px;
    cursor: grab; user-select: none;
    border-bottom: 1px solid #1c1c1c;
  }
  .win-titlebar:active { cursor: grabbing; }
  .win-title { flex: 1; font-size: 13px; font-weight: 500; opacity: 0.9; }
  .win-close {
    width: 22px; height: 22px; border-radius: 50%; border: none;
    background: #e95420; color: #fff; cursor: pointer; font-size: 14px;
    display: flex; align-items: center; justify-content: center;
    line-height: 1; transition: background .15s;
  }
  .win-close:hover { background: #f47042; }
  .win-body { flex: 1; overflow: auto; position: relative; }

  /* Files app */
  #files-window { width: 560px; height: 380px; left: 80px; top: 70px; }
  .files-toolbar {
    display: flex; align-items: center; gap: 8px; padding: 8px 10px;
    background: #1e1e1e; border-bottom: 1px solid #111;
  }
  #files-up {
    padding: 5px 12px; background: #3c3c3c; color: #fff; border: 1px solid #555;
    border-radius: 6px; cursor: pointer; font-size: 13px;
  }
  #files-up:hover { background: #4a4a4a; }
  #files-path {
    flex: 1; font-family: "DejaVu Sans Mono", monospace; font-size: 12px;
    background: #141414; padding: 6px 10px; border-radius: 6px;
    border: 1px solid #333; color: #e0e0e0; overflow: hidden; text-overflow: ellipsis; white-space: nowrap;
  }
  .files-list {
    display: grid; grid-template-columns: repeat(auto-fill, minmax(96px, 1fr));
    gap: 6px; padding: 14px;
  }
  .fs-item {
    display: flex; flex-direction: column; align-items: center; gap: 6px;
    padding: 10px 6px; border-radius: 8px; cursor: pointer; text-align: center;
    font-size: 12px; transition: background .12s;
  }
  .fs-item:hover { background: rgba(233, 84, 32, 0.18); }
  .fs-icon { font-size: 34px; line-height: 1; }
  .fs-name { word-break: break-word; max-width: 90px; }

  /* Notepad app */
  #notepad-window { width: 560px; height: 400px; left: 200px; top: 90px; }
  .notepad-tabs {
    display: flex; align-items: center; gap: 4px; padding: 6px 8px;
    background: #1e1e1e; border-bottom: 1px solid #111; flex-wrap: wrap;
  }
  .tab {
    display: flex; align-items: center; gap: 6px; padding: 5px 10px;
    background: #2b2b2b; border: 1px solid #3a3a3a; border-radius: 6px;
    font-size: 12px; cursor: pointer; color: #ccc; max-width: 160px;
  }
  .tab.active { background: #e95420; color: #fff; border-color: #e95420; }
  .tab .tab-name { overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
  .tab .tab-x {
    width: 16px; height: 16px; border-radius: 50%; background: rgba(255,255,255,0.2);
    display: flex; align-items: center; justify-content: center; font-size: 11px;
    border: none; cursor: pointer; color: inherit;
  }
  .tab.active .tab-x { background: rgba(0,0,0,0.25); }
  .tab .tab-x:hover { background: rgba(255,255,255,0.4); }
  #new-tab {
    padding: 5px 10px; background: #3c3c3c; color: #fff; border: 1px solid #555;
    border-radius: 6px; cursor: pointer; font-size: 14px; line-height: 1;
  }
  #new-tab:hover { background: #4a4a4a; }
  #editor {
    width: 100%; height: calc(100% - 0px); min-height: 200px;
    background: #1e1e1e; color: #e8e8e8; border: none; outline: none;
    padding: 12px; font-family: "DejaVu Sans Mono", monospace; font-size: 13px;
    resize: none; display: block; flex: 1;
  }
  .editor-wrap { flex: 1; display: flex; }
  .editor-wrap #editor { flex: 1; }

  /* Desktop icons */
  .desktop-icons {
    position: absolute; top: 40px; left: 16px; display: flex; flex-direction: column; gap: 14px;
  }
  .desktop-icon {
    width: 84px; display: flex; flex-direction: column; align-items: center; gap: 4px;
    cursor: pointer; padding: 6px; border-radius: 6px; text-align: center;
  }
  .desktop-icon:hover { background: rgba(255,255,255,0.08); }
  .desktop-icon .ic { font-size: 38px; }
  .desktop-icon .lbl { font-size: 12px; text-shadow: 0 1px 2px rgba(0,0,0,0.8); }
</style>
</head>
<body>
<div id="desktop">
  <div id="topbar">
    <span class="activities">Activities</span>
    <span id="clock">--:--</span>
  </div>

  <div class="desktop-icons">
    <div class="desktop-icon" id="icon-files">
      <div class="ic">📁</div><div class="lbl">Files</div>
    </div>
    <div class="desktop-icon" id="icon-notepad">
      <div class="ic">📝</div><div class="lbl">Notepad</div>
    </div>
  </div>

  <!-- Files Window -->
  <div id="files-window" class="window hidden">
    <div class="win-titlebar">
      <span class="win-title">Files</span>
      <button class="win-close" data-target="files-window" aria-label="Close">×</button>
    </div>
    <div class="files-toolbar">
      <button id="files-up">↑ Up</button>
      <div id="files-path">/</div>
    </div>
    <div class="win-body">
      <div class="files-list" id="files-list"></div>
    </div>
  </div>

  <!-- Notepad Window -->
  <div id="notepad-window" class="window hidden">
    <div class="win-titlebar">
      <span class="win-title">Notepad</span>
      <button class="win-close" data-target="notepad-window" aria-label="Close">×</button>
    </div>
    <div class="notepad-tabs" id="tabs"></div>
    <div class="editor-wrap">
      <textarea id="editor" placeholder="Type something..."></textarea>
    </div>
    <div style="display:flex; padding:6px 8px; background:#1e1e1e; border-top:1px solid #111;">
      <button id="new-tab">+ New Tab</button>
    </div>
  </div>

  <div id="taskbar">
    <button id="open-files" title="Files">📁</button>
    <button id="open-notepad" title="Notepad">📝</button>
  </div>
</div>

<script>
/* ============ Clock ============ */
function updateClock(){
  const d = new Date();
  const hh = String(d.getHours()).padStart(2,'0');
  const mm = String(d.getMinutes()).padStart(2,'0');
  document.getElementById('clock').textContent = hh+':'+mm;
}
updateClock(); setInterval(updateClock, 1000);

/* ============ Window dragging ============ */
function makeDraggable(win){
  const bar = win.querySelector('.win-titlebar');
  let dragging=false, ox=0, oy=0;
  bar.addEventListener('mousedown', e=>{
    if(e.target.classList.contains('win-close')) return;
    dragging=true;
    const rect = win.getBoundingClientRect();
    ox = e.clientX - rect.left;
    oy = e.clientY - rect.top;
    win.style.left = rect.left+'px';
    win.style.top = rect.top+'px';
    win.style.right='auto'; win.style.bottom='auto';
    bringToFront(win);
    e.preventDefault();
  });
  document.addEventListener('mousemove', e=>{
    if(!dragging) return;
    let x = e.clientX - ox;
    let y = e.clientY - oy;
    x = Math.max(0, Math.min(window.innerWidth - 80, x));
    y = Math.max(28, Math.min(window.innerHeight - 40, y));
    win.style.left = x+'px';
    win.style.top = y+'px';
  });
  document.addEventListener('mouseup', ()=>{ dragging=false; });
}
function bringToFront(win){
  document.querySelectorAll('.window').forEach(w=> w.style.zIndex = 10);
  win.style.zIndex = 50;
}

/* ============ Window open/close ============ */
function openWindow(id){
  const w = document.getElementById(id);
  w.classList.remove('hidden');
  bringToFront(w);
}
function closeWindow(id){
  document.getElementById(id).classList.add('hidden');
}
document.querySelectorAll('.win-close').forEach(btn=>{
  btn.addEventListener('click', ()=> closeWindow(btn.dataset.target));
});
document.getElementById('open-files').addEventListener('click', ()=> openWindow('files-window'));
document.getElementById('open-notepad').addEventListener('click', ()=> openWindow('notepad-window'));
document.getElementById('icon-files').addEventListener('dblclick', ()=> openWindow('files-window'));
document.getElementById('icon-notepad').addEventListener('dblclick', ()=> openWindow('notepad-window'));

document.querySelectorAll('.window').forEach(makeDraggable);

/* ============ Fake filesystem ============ */
const FS = {
  '/': { type:'dir', children:['bin','etc','home','usr','var'] },
  '/bin': { type:'dir', children:['bash','ls','cp','mv','cat'] },
  '/etc': { type:'dir', children:['hostname','hosts','passwd','fstab','resolv.conf'] },
  '/home': { type:'dir', children:['user'] },
  '/home/user': { type:'dir', children:['Documents','Downloads','Pictures','notes.txt','readme.md'] },
  '/home/user/Documents': { type:'dir', children:['report.txt','budget.csv','todo.txt'] },
  '/home/user/Downloads': { type:'dir', children:['ubuntu-22.04.iso','installer.deb','image.png'] },
  '/home/user/Pictures': { type:'dir', children:['wallpaper.jpg','screenshot.png','vacation.jpg'] },
  '/usr': { type:'dir', children:['bin','lib','share','local'] },
  '/usr/bin': { type:'dir', children:['python3','node','git','curl'] },
  '/usr/lib': { type:'dir', children:['libc.so','libssl.so'] },
  '/usr/share': { type:'dir', children:['doc','icons','fonts'] },
  '/usr/local': { type:'dir', children:['bin','etc'] },
  '/var': { type:'dir', children:['log','tmp','lib','cache'] },
  '/var/log': { type:'dir', children:['syslog','auth.log','kern.log'] },
  '/var/tmp': { type:'dir', children:['session.cache'] },
  '/var/lib': { type:'dir', children:['dpkg','apt'] },
  '/var/cache': { type:'dir', children:['apt','fonts'] },
  // files
  '/home/user/notes.txt': { type:'file', content:'Remember to backup the system.' },
  '/home/user/readme.md': { type:'file', content:'# Welcome\nThis is your home folder.' },
  '/home/user/Documents/report.txt': { type:'file', content:'Q3 report draft...' },
  '/home/user/Documents/budget.csv': { type:'file', content:'item,price\nrent,1200\nfood,300' },
  '/home/user/Documents/todo.txt': { type:'file', content:'- [ ] buy milk\n- [x] walk dog' },
  '/etc/hostname': { type:'file', content:'ubuntu-desktop' },
  '/etc/hosts': { type:'file', content:'127.0.0.1 localhost' },
  '/etc/passwd': { type:'file', content:'root:x:0:0:root:/root:/bin/bash\nuser:x:1000:1000:User:/home/user:/bin/bash' },
};

function isDir(path){ return FS[path] && FS[path].type==='dir'; }
function isFile(path){ return FS[path] && FS[path].type==='file'; }
function parentPath(p){
  if(p==='/') return '/';
  const parts = p.split('/').filter(Boolean);
  parts.pop();
  return parts.length ? '/'+parts.join('/') : '/';
}
function joinPath(base, name){
  return base==='/' ? '/'+name : base+'/'+name;
}

let currentPath = '/';
const filesListEl = document.getElementById('files-list');
const filesPathEl = document.getElementById('files-path');

function renderFiles(){
  filesPathEl.textContent = currentPath;
  filesListEl.innerHTML = '';
  const node = FS[currentPath];
  if(!node || node.type!=='dir'){
    filesListEl.innerHTML = '<div style="padding:14px;color:#999;">Empty or invalid directory</div>';
    return;
  }
  const children = node.children || [];
  children.forEach(name=>{
    const full = joinPath(currentPath, name);
    const child = FS[full];
    const isFolder = child ? child.type==='dir' : name.indexOf('.')===-1; // treat unknown as dir-ish? no—treat as file
    const folder = child ? child.type==='dir' : false;
    const el = document.createElement('div');
    el.className = 'fs-item';
    el.dataset.path = full;
    el.dataset.name = name;
    el.innerHTML = '<div class="fs-icon">'+(folder?'📁':'📄')+'</div>'+
                   '<div class="fs-name">'+name+'</div>';
    el.addEventListener('dblclick', ()=>{
      if(folder){
        currentPath = full;
        renderFiles();
      } else if(isFile(full)){
        // open in notepad
        openWindow('notepad-window');
        loadFileIntoNewTab(full, child.content || '');
      }
    });
    filesListEl.appendChild(el);
  });
  if(children.length===0){
    filesListEl.innerHTML = '<div style="padding:14px;color:#999;grid-column:1/-1;">This folder is empty</div>';
  }
}

document.getElementById('files-up').addEventListener('click', ()=>{
  if(currentPath==='/') return;
  currentPath = parentPath(currentPath);
  renderFiles();
});

renderFiles();

/* ============ Notepad with tabs + localStorage ============ */
const STORAGE_KEY = 'ubuntu_notepad_tabs_v1';
let tabs = [];        // [{id, name, content}]
let activeTabId = null;

function loadTabs(){
  try{
    const raw = localStorage.getItem(STORAGE_KEY);
    if(raw){
      const parsed = JSON.parse(raw);
      if(Array.isArray(parsed) && parsed.length){
        tabs = parsed.map(t=>({ id: t.id, name: t.name, content: t.content||'' }));
        activeTabId = tabs[0].id;
        return;
      }
    }
  }catch(e){}
  // default one tab
  tabs = [{ id: uid(), name: 'Untitled', content: '' }];
  activeTabId = tabs[0].id;
}

function saveTabs(){
  try{
    localStorage.setItem(STORAGE_KEY, JSON.stringify(tabs));
  }catch(e){}
}

function uid(){ return 't'+Math.random().toString(36).slice(2,9)+Date.now().toString(36).slice(-4); }

function renderTabs(){
  const tabsEl = document.getElementById('tabs');
  tabsEl.innerHTML = '';
  tabs.forEach(t=>{
    const el = document.createElement('div');
    el.className = 'tab' + (t.id===activeTabId ? ' active' : '');
    el.dataset.id = t.id;
    const name = document.createElement('span');
    name.className = 'tab-name';
    name.textContent = t.name;
    const x = document.createElement('button');
    x.className = 'tab-x';
    x.textContent = '×';
    x.title = 'Close tab';
    x.addEventListener('click', e=>{
      e.stopPropagation();
      closeTab(t.id);
    });
    el.appendChild(name);
    el.appendChild(x);
    el.addEventListener('click', ()=>{
      activeTabId = t.id;
      renderTabs();
      loadEditor();
    });
    tabsEl.appendChild(el);
  });
}

function loadEditor(){
  const t = tabs.find(x=>x.id===activeTabId);
  document.getElementById('editor').value = t ? t.content : '';
}

function getActiveTab(){ return tabs.find(x=>x.id===activeTabId); }

document.getElementById('editor').addEventListener('input', e=>{
  const t = getActiveTab();
  if(t){
    t.content = e.target.value;
    saveTabs();
  }
});

document.getElementById('new-tab').addEventListener('click', ()=>{
  const t = { id: uid(), name: 'Untitled', content: '' };
  tabs.push(t);
  activeTabId = t.id;
  renderTabs();
  loadEditor();
  saveTabs();
  document.getElementById('editor').focus();
});

function closeTab(id){
  const idx = tabs.findIndex(x=>x.id===id);
  if(idx===-1) return;
  tabs.splice(idx,1);
  if(tabs.length===0){
    const t = { id: uid(), name: 'Untitled', content: '' };
    tabs.push(t);
    activeTabId = t.id;
  } else {
    activeTabId = tabs[Math.min(idx, tabs.length-1)].id;
  }
  renderTabs();
  loadEditor();
  saveTabs();
}

function loadFileIntoNewTab(path, content){
  const name = path.split('/').pop();
  const t = { id: uid(), name: name, content: content };
  tabs.push(t);
  activeTabId = t.id;
  renderTabs();
  loadEditor();
  saveTabs();
}

// init
loadTabs();
renderTabs();
loadEditor();
</script>
</body>
</html>
